(function($){let settings=[];$.fn.table=function(options,params){let setting={};let table=null;if(typeof options==="object"){table=$(this);let currentId=table.attr("id");let instance={id:currentId,endpoint:"",type:"GET",mappingFunction:function(data){return""},success:function(e,data){return},fail:function(error){return},messageNoResult:"No records returned",messageErrorOccured:"Error occurred",messageNotFound:"Data not found",cssClassNoResult:"text-center",messageLoading:"Loading data...",params:{},data:[],async:true};setting=Object.assign(instance,options);settings.push(setting);refresh(table,setting);return table}if(typeof options==="string"){table=$(this);let currentId=table.attr("id");if(options=="refresh"){let foundSetting=settings.find((e=>e.id==currentId));if(foundSetting){if(params!=undefined)foundSetting.params=params;setting=Object.assign(foundSetting,options);settings.push(setting);refresh(table,setting)}}if(options=="load"){let foundSettings=settings.find((e=>e.id==currentId));let foundSetting=foundSettings[0];if(params!=undefined)foundSetting.data=params;if(foundSettings.length>0){setting=Object.assign(foundSettings[0],options);settings.push(setting);load(setting)}}if(options=="clear"){clear(table)}}return table};function clear(table){table.find("tbody").empty()}function refresh(table,setting){generateTableBody(table,setting,0);let parameters={context:document.body,dataType:"json",async:setting.async,statusCode:{404:function(response){setting.data=response;generateTableBody(table,setting,404)},500:function(response){setting.data=response;generateTableBody(table,setting,500)},200:function(response){setting.data=response;generateTableBody(table,setting,200)}},complete:function(data){setting.success()}};if(setting.type.toUpperCase()=="GET"){let queryString="";try{queryString=jQuery.param(setting.params)}catch(exception){queryString=""}parameters.url=setting.endpoint+"?"+queryString}else if(setting.type.toUpperCase()=="POST"){parameters.url=setting.endpoint;parameters.data=setting.params}else{setting.fail("Unsupported call type");return}$.ajax(parameters)}function load(table,setting){generateTableBody(table,setting,200);setting.success()}function generateTableBody(table,setting,code){let html="";let tbody=table.find("tbody");let colspanHtml=getColspan(table);tbody.find("tr").remove();if(code==0){html=`<tr>\n                       <td ${colspanHtml} class="busy ${setting.cssClassNoResult}"><strong>${setting.messageLoading}</strong></td>\n                   </tr>`}if(code==404){html=`<tr>\n                       <td ${colspanHtml} class="${setting.cssClassNoResult}">${setting.messageNotFound}</td>\n                   </tr>`}if(code==500){html=`<tr>\n                       <td ${colspanHtml} class="${setting.cssClassNoResult}">${setting.messageErrorOccured}</td>\n                   </tr>`}if(code==200){html=setting.mappingFunction(setting.data);if(html==""){html=`<tr>\n                           <td ${colspanHtml} class="${setting.cssClassNoResult}"><strong>${setting.messageNoResult}</strong></td>\n                       </tr>`}}tbody.html(html)}function getColspan(table){let colspan=1;table.find("thead > tr:nth-child(1) th").each((function(){if($(this).attr("colspan")){colspan+=+$(this).attr("colspan")}else{colspan++}}));let colspanHtml="";if(colspan>1)colspanHtml=`colspan="${colspan}"`;return colspanHtml}})(jQuery);